<script lang="ts">
  import type{BrowserStorageStatus}from'@simbot/persistence';import type{Persona,PromptPreset}from'@simbot/risu';import type{ProviderConfig,ProviderId}from'@simbot/session';import Icon from'@simbot/ui/Icon.svelte';import OverlayGuard from'@simbot/ui/OverlayGuard.svelte';import PromptPanel from'./PromptPanel.svelte';import PersonaPanel from'./PersonaPanel.svelte';import PresetToggleControls from'./PresetToggleControls.svelte';
  import SettingsStorageRecovery from'./SettingsStorageRecovery.svelte';
  type Aux={provider:ProviderId;model:string;apiKey:string};type Settings=ProviderConfig&{endpoint:string;voyageKey:string;assetWidth:number;keepSimulationOpen:boolean;auxEnabled:boolean;auxSlots:{translation:Aux;emotion:Aux;memory:Aux}};
  interface PromptUi{presets:PromptPreset[];active:PromptPreset;toggleValues:Record<string,string>;ontoggle:(key:string,value:string)=>void;onselect:(id:string)=>void;onchange:(p:PromptPreset)=>void;onnew:()=>void;onclone:()=>void;onrename:()=>void;onremove:()=>void;onimport:(file:File)=>void;onexport:()=>void}
  interface PersonaUi{personas:Persona[];active:Persona;bound:boolean;onselect:(id:string)=>void;onsave:(p:Persona)=>void;onnew:()=>void;onclone:()=>void;onremove:()=>void;onbind:(v:boolean)=>void;onimport:(file:File)=>void;onexport:()=>void}
  interface MemoryStatus{total:number;approved:number;candidates:number;recentRecall:number;semantic:boolean}
  import {diagnostics,diagnosticLevels,diagnosticLevelLabel,type DiagnosticLevel} from './diagnostics.svelte.ts';
  const levelHint:Record<DiagnosticLevel,string>={error:'실패한 처리 단계',warn:'예산 초과·차단된 효과·빈 결과',info:'턴 흐름과 처리 과정',trace:'프롬프트·CBS·정규식 내역 (무겁고 대화 내용이 포함됩니다)'};
  type SettingsTab='model'|'toggles'|'prompt'|'persona'|'chat'|'diagnostics'|'other';type NumericKey='temperature'|'maxTokens'|'maxContext'|'topP'|'topK'|'frequencyPenalty'|'presencePenalty'|'seed';type Param={key:NumericKey;label:string;min:number;max:number;step:number;preview:number;providers?:ProviderId[];exclude?:ProviderId[];description:string;defaultValue:undefined};
  let{settings,providerChoices,models,promptUi,personaUi,memoryStatus={total:0,approved:0,candidates:0,recentRecall:0,semantic:false},storageStatus,storageBackend='memory',initialTab='model',onsave,onclose,onprovider,onmodels,onstorage,onconsole,onmemory,numberSetting}:{settings:Settings;providerChoices:Array<{id:ProviderId;label:string}>;models:Array<{id:string;label:string}>;promptUi:PromptUi;personaUi:PersonaUi;memoryStatus?:MemoryStatus;storageStatus:BrowserStorageStatus;storageBackend?:string;initialTab?:SettingsTab;onsave:()=>void;onclose:()=>void;onprovider:(id:ProviderId)=>void;onmodels:()=>void|Promise<void>;onstorage:()=>void;onconsole:()=>void;onmemory:()=>void;numberSetting:(key:keyof ProviderConfig,value:string)=>void}=$props();let tab=$state<SettingsTab>('model'),modelLoading=$state(false),modelNotice=$state('');
  $effect(()=>{tab=initialTab;});
  const params:Param[]=[
    {key:'temperature',label:'Temperature',min:0,max:2,step:.05,preview:1,description:'낮을수록 안정적이고 높을수록 다양한 답변을 만듭니다.',defaultValue:undefined},
    {key:'maxTokens',label:'최대 응답 토큰',min:1,max:131072,step:1,preview:4096,description:'한 번에 생성할 답변의 최대 길이입니다.',defaultValue:undefined},
    {key:'maxContext',label:'최대 문맥 토큰',min:0,max:2000000,step:256,preview:24000,description:'최근 대화 토큰 예산. Risu처럼 예산을 넘으면 오래된 대화부터 잘립니다. 0 = 무제한. 잘린 대화도 기록에는 전부 남습니다.',defaultValue:undefined},
    {key:'topP',label:'Top P',min:0,max:1,step:.01,preview:1,description:'확률이 높은 후보 묶음의 범위를 조절합니다.',defaultValue:undefined},
    {key:'topK',label:'Top K',min:1,max:1000,step:1,preview:40,providers:['anthropic','google','vertex'],description:'매 순간 고려할 상위 후보 수입니다.',defaultValue:undefined},
    {key:'frequencyPenalty',label:'빈도 페널티',min:-2,max:2,step:.1,preview:0,exclude:['anthropic','google','vertex'],description:'이미 자주 쓴 표현의 반복을 줄입니다.',defaultValue:undefined},
    {key:'presencePenalty',label:'존재 페널티',min:-2,max:2,step:.1,preview:0,exclude:['anthropic','google','vertex'],description:'한 번이라도 쓴 주제의 반복을 줄입니다.',defaultValue:undefined},
    {key:'seed',label:'Seed',min:0,max:2147483647,step:1,preview:0,exclude:['anthropic'],description:'지원 모델에서 결과 재현에 쓰는 정수입니다.',defaultValue:undefined}
  ];
  const supported=(param:Param)=>(!param.providers||param.providers.includes(settings.provider))&&!param.exclude?.includes(settings.provider),size=(value:number|null)=>value===null?'확인할 수 없음':value>=1024**3?`${(value/1024**3).toFixed(1)}GB`:`${(value/1024**2).toFixed(1)}MB`;
  function setParam(param:Param,value:string){if(value.trim()===''){numberSetting(param.key,'');return;}const parsed=Number(value);if(!Number.isFinite(parsed))return;numberSetting(param.key,String(Math.min(param.max,Math.max(param.min,parsed))));}
  async function refreshModelChoices(){modelLoading=true;modelNotice='';try{await onmodels();modelNotice=`${models.length}개 모델을 불러왔습니다.`;}catch(error){modelNotice=`모델 목록을 불러오지 못했습니다: ${error instanceof Error?error.message:String(error)}`;}finally{modelLoading=false;}}
</script>
<OverlayGuard label="전체 설정" {onclose} strong zIndex={80}>
  <section class="settings"><nav><h2><Icon name="settings"/> 설정</h2><button class:active={tab==='model'} onclick={()=>tab='model'}>모델·파라미터</button>{#if promptUi.active.toggles?.length}<button class:active={tab==='toggles'} onclick={()=>tab='toggles'}>프리셋 토글</button>{/if}<button class:active={tab==='prompt'} onclick={()=>tab='prompt'}>프롬프트</button><button class:active={tab==='persona'} onclick={()=>tab='persona'}>페르소나</button><button class:active={tab==='chat'} onclick={()=>tab='chat'}>채팅 보기</button><button class:active={tab==='diagnostics'} onclick={()=>tab='diagnostics'}>진단</button><button class:active={tab==='other'} onclick={()=>tab='other'}>기타</button><span></span><button class="close" onclick={onclose}>닫기</button></nav>
  <div class="mobile-nav"><label><span>설정 메뉴</span><select aria-label="설정 메뉴" value={tab} onchange={(event)=>tab=event.currentTarget.value as SettingsTab}><option value="model">모델·파라미터</option>{#if promptUi.active.toggles?.length}<option value="toggles">프리셋 토글</option>{/if}<option value="prompt">프롬프트</option><option value="persona">페르소나</option><option value="chat">채팅 보기</option><option value="diagnostics">진단</option><option value="other">기타</option></select></label><button aria-label="설정 닫기" onclick={onclose}>닫기</button></div><main>
  {#if tab==='model'}<h3>모델·파라미터</h3><label>프로바이더<select value={settings.provider} onchange={(e)=>{modelNotice='';onprovider(e.currentTarget.value as ProviderId);}}>{#each providerChoices as choice}<option value={choice.id}>{choice.label}</option>{/each}</select></label><fieldset class="model-picker"><legend>모델 선택</legend><label>추천·사용 가능 모델<select value={settings.model} onchange={(event)=>settings.model=event.currentTarget.value}>{#if settings.model&&!models.some(item=>item.id===settings.model)}<option value={settings.model}>{settings.model} · 직접 입력</option>{/if}{#each models as item}<option value={item.id}>{item.label}</option>{/each}</select></label><label>호출명 직접 입력<input bind:value={settings.model} spellcheck="false"/></label><div class="model-refresh"><button class="sub" disabled={modelLoading} onclick={()=>void refreshModelChoices()}>{modelLoading?'모델 목록 불러오는 중…':'계정에서 사용 가능한 모델 불러오기'}</button><small>목록에 없어도 정확한 호출명을 직접 입력할 수 있습니다. 키가 없거나 조회를 지원하지 않으면 기본 추천 목록을 사용합니다.</small></div>{#if modelNotice}<p class="model-notice" aria-live="polite">{modelNotice}</p>{/if}</fieldset>{#if settings.provider==='vertex'}<label>서비스 계정 JSON<textarea rows="5" bind:value={settings.apiKey}></textarea></label><label>리전<input bind:value={settings.location}/></label>{:else}<label>{settings.provider==='copilot'?'GitHub OAuth 토큰':settings.provider==='ollama'?'API 키 (선택 — 로컬은 비워둠)':'API 키'}<textarea rows="3" bind:value={settings.apiKey}></textarea></label>{/if}{#if settings.provider==='custom'}<label>API 주소<input bind:value={settings.endpoint}/></label>{/if}{#if settings.provider==='ollama'}<label>Base URL<input bind:value={settings.endpoint} placeholder="http://localhost:11434 (비우면 로컬 기본)"/></label><small class="hint">로컬 Ollama는 API 키가 필요 없습니다(비워두세요). 브라우저에서 접속하려면 Ollama 실행 전에 <code>OLLAMA_ORIGINS={location.origin}</code> 환경변수를 설정해야 CORS가 열립니다. Ollama Cloud는 https://ollama.com + API 키.</small>{/if}<details open><summary>고급 생성 파라미터</summary><p class="hint">값을 비우면 선택한 AI 제공자의 기본값을 사용합니다. 최대 문맥 토큰만 빈 값이 무제한(0)으로 저장됩니다.</p><div class="grid">{#each params.filter(supported) as param}<div class="parameter"><div class="parameter-head"><label for={`number-${param.key}`}>{param.label}</label><button class="reset" disabled={param.key==='maxContext'?settings.maxContext===0:settings[param.key]===undefined} onclick={()=>setParam(param,'')}>{param.key==='maxContext'?'무제한':'제공자 기본값'}</button></div><div class="controls"><input aria-label={`${param.label} 슬라이더`} title={settings[param.key]===undefined?'표시 위치만 참고값이며, 현재는 제공자 기본값을 사용합니다.':''} type="range" min={param.min} max={param.max} step={param.step} value={settings[param.key]??param.preview} oninput={(e)=>setParam(param,e.currentTarget.value)}/><input id={`number-${param.key}`} aria-label={`${param.label} 숫자`} type="number" min={param.min} max={param.max} step={param.step} value={settings[param.key]??''} placeholder={param.key==='maxContext'?'0 = 무제한':'기본값'} oninput={(e)=>setParam(param,e.currentTarget.value)}/></div><small>{param.description} 범위 {param.min.toLocaleString()}–{param.max.toLocaleString()}</small></div>{/each}</div></details>
  {:else if tab==='toggles'}<h3>프리셋 토글</h3><p class="hint">이 회차에만 적용되며 대화 메시지를 추가하지 않습니다. 다음 답변부터 바로 반영됩니다.</p><PresetToggleControls toggles={promptUi.active.toggles??[]} values={promptUi.toggleValues} onchange={promptUi.ontoggle}/>
  {:else if tab==='prompt'}<h3>프롬프트</h3><PromptPanel {...promptUi}/>
  {:else if tab==='persona'}<h3>페르소나</h3><PersonaPanel {...personaUi}/>
  {:else if tab==='chat'}<h3>채팅 보기</h3><p class="hint">채팅 본문에 나오는 이미지의 최대 크기를 조절합니다. 이미지를 누르면 원본 크기로 확대해 볼 수 있습니다.</p><fieldset class="chat-view"><legend>본문 이미지 크기</legend><div class="view-presets"><button class:active={settings.assetWidth===16} onclick={()=>settings.assetWidth=16}>작게</button><button class:active={settings.assetWidth===32} onclick={()=>settings.assetWidth=32}>보통</button><button class:active={settings.assetWidth===40} onclick={()=>settings.assetWidth=40}>크게</button><button class:active={settings.assetWidth===48} onclick={()=>settings.assetWidth=48}>화면 너비</button></div><label>세밀 조절 · {settings.assetWidth}rem<input aria-label="본문 이미지 최대 너비" type="range" min="8" max="48" step="1" bind:value={settings.assetWidth}/></label><small>설정은 저장한 뒤 모든 채팅에 같이 적용됩니다.</small></fieldset>
  {:else if tab==='diagnostics'}<h3>진단</h3><p class="hint">콘솔은 문제가 있을 때만 보는 창이 아닙니다. 언제든 열어서 지금 무슨 일이 일어나는지 볼 수 있고, 이상하면 그대로 복사해 넘기면 됩니다. 데스크톱에서는 백틱(`) 키로도 열립니다.</p><button class="sub" onclick={onconsole}><Icon name="badge" size={14}/> 콘솔 열기{#if diagnostics.count} · {diagnostics.count}건{/if}</button>
  <fieldset><legend>기록할 레벨</legend>{#each diagnosticLevels as level}<label class="toggle"><input type="checkbox" checked={diagnostics.levels[level]} onchange={(event)=>diagnostics.levels[level]=(event.currentTarget as HTMLInputElement).checked}/><span>{diagnosticLevelLabel[level]}</span><small>{levelHint[level]}</small></label>{/each}</fieldset>
  <p class="hint">추적은 꺼져 있으면 <b>만들지도 않습니다</b> — 켜면 턴마다 수백 줄이 쌓이고 프롬프트 원문이 흐릅니다. 그 로그를 남에게 보낼 때는 대화 내용이 포함된다는 뜻입니다. 필요한 순간에만 켜세요.</p>
  <p class="hint">기록은 메모리에만 남습니다(새로고침하면 사라집니다). API 키는 기록되는 시점에 지워집니다.</p>
  {:else}<h3>기타</h3><fieldset><legend>시뮬레이션</legend><label class="toggle"><input type="checkbox" bind:checked={settings.keepSimulationOpen}/> 관리 행동 후 관리 화면 유지</label><small>서사는 뒤의 채팅에 쌓이며, 후속 결정은 관리 화면 아래의 같은 결정 카드에서 이어갈 수 있습니다.</small></fieldset><fieldset class="memory-settings"><legend>장기기억 검색</legend><div class="memory-state"><b>{memoryStatus.semantic?'Voyage 의미 검색':'기본 기억 검색'} 사용 중</b><span>기억 {memoryStatus.total}건 · 확정 {memoryStatus.approved}건 · 검토 대기 {memoryStatus.candidates}건{#if memoryStatus.recentRecall} · 최근 회상 {memoryStatus.recentRecall}건{/if}</span></div><p>키가 없어도 장기기억의 저장·회상·검토는 작동합니다. Voyage를 연결하면 표현이 달라도 뜻이 비슷한 오래된 기억을 더 잘 찾습니다.</p><label>Voyage API 키 · 선택<input type="password" bind:value={settings.voyageKey} placeholder="비워도 장기기억은 계속 작동합니다"/></label><button class="sub" onclick={onmemory}>기억 수첩 열기</button></fieldset><fieldset class="storage"><legend>내 카드·채팅 저장</legend><dl><div><dt>영구 저장</dt><dd class:ok={storageStatus.persistent===true} class:warn={storageStatus.persistent===false}>{!storageStatus.supported?'이 브라우저는 확인 불가':storageStatus.persistent===true?'허용됨':storageStatus.persistent===false?'허용되지 않음':'확인 중'}</dd></div><div><dt>사용량</dt><dd>{size(storageStatus.usage)} / {size(storageStatus.quota)}</dd></div></dl>{#if storageStatus.error}<small>저장 상태 확인 실패: {storageStatus.error}</small>{/if}<button class="sub" onclick={onstorage}>영구 저장 다시 요청</button><small>브라우저에 삭제하지 말아 달라고 요청하는 기능이며 보장을 뜻하지 않습니다. 중요한 플레이는 현재 채팅 내보내기와 원본 카드 파일을 함께 백업하세요.</small><small>카드 이미지·에셋은 로컬에 남지만, 대화에 필요한 카드 설명·로어·프롬프트 텍스트는 선택한 AI 제공자로 전송됩니다.</small></fieldset><label class="toggle"><input type="checkbox" bind:checked={settings.auxEnabled}/> 번역·감정·메모리에 별도 모델 사용</label>{#if settings.auxEnabled}{#each Object.entries(settings.auxSlots) as [name,slot]}<fieldset><legend>{name}</legend><select bind:value={slot.provider}>{#each providerChoices as choice}<option value={choice.id}>{choice.label}</option>{/each}</select><input bind:value={slot.model} placeholder="모델 ID"/><textarea bind:value={slot.apiKey} placeholder="비우면 본 모델 키 재사용"></textarea></fieldset>{/each}{/if}{/if}
  {#if tab==='other'}<SettingsStorageRecovery backend={storageBackend}/>{/if}
  <footer><button onclick={onclose}>취소</button><button class="primary" onclick={onsave}>저장</button></footer></main></section>
</OverlayGuard>
<style>.memory-settings{border-color:#5a4c31;background:#1e1b15}.memory-settings p{margin:0;color:#aaa08c;font-size:12px;line-height:1.5}.memory-state{display:grid;gap:4px;padding:9px;border-radius:6px;background:#282318}.memory-state b{color:#ead6a8}.memory-state span{color:#aaa08c;font-size:11px}.settings{box-sizing:border-box;width:100%;height:100%;display:grid;grid-template-columns:220px 1fr;overflow:hidden;border:1px solid #343842;background:#17191e;color:#e9e9eb;box-shadow:0 24px 80px #000a}nav{display:flex;flex-direction:column;gap:5px;padding:18px 12px;background:#101115;border-right:1px solid #292c34}nav h2{display:flex;align-items:center;gap:9px;margin:0 8px 20px;font-size:18px}nav button{padding:10px 12px;text-align:left;border:0;border-radius:6px;background:transparent;color:#9ca3af}nav button:hover,nav button.active{background:#272a31;color:#fff}nav button:focus-visible,button:focus-visible,input:focus-visible,textarea:focus-visible,select:focus-visible{outline:2px solid #6c98f4;outline-offset:2px}nav span{flex:1}.mobile-nav{display:none}main{min-height:0;overflow:auto;padding:24px 30px}h3{margin:0 0 20px}label{display:grid;gap:5px;margin:10px 0;font-size:12px;color:#bbc0ca}input,select,textarea{box-sizing:border-box;min-width:0;padding:9px;border:1px solid #3b3f49;border-radius:6px;background:#111318;color:#eee}.hint{margin:8px 0;color:#9ca3af;font-size:12px}.grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:12px 16px}.parameter{display:grid;gap:7px;padding:12px;border:1px solid #30343d;border-radius:8px;background:#121419}.parameter-head{display:flex;align-items:center;justify-content:space-between;gap:8px}.parameter-head label{margin:0;font-weight:600;color:#d6d9df}.controls{display:grid;grid-template-columns:minmax(100px,1fr) 110px;align-items:center;gap:10px}.controls input[type="range"]{padding:0}.parameter small{color:#8f96a3;line-height:1.4}.reset{padding:4px 7px;border:0;background:transparent;color:#8fb2ff;font-size:11px}.reset:disabled{opacity:.4}.sub,footer button{padding:8px 12px;border:1px solid #3b3f49;border-radius:6px;background:#24272e;color:#ddd}details{margin:18px 0}summary{cursor:pointer}.toggle{display:flex;align-items:center;gap:8px}fieldset{margin:12px 0;border:1px solid #343842;border-radius:7px;display:grid;gap:8px}.storage dl{display:grid;gap:6px;margin:0}.storage dl div{display:flex;justify-content:space-between;gap:12px}.storage dt{color:#9299a7}.storage dd{margin:0}.storage .ok{color:#9bd19a}.storage .warn{color:#e9c875}.chat-view{gap:12px}.view-presets{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:7px}.view-presets button{min-height:38px;padding:7px;border:1px solid #3b3f49;border-radius:6px;background:#24272e;color:#ddd}.view-presets button.active{border-color:#6c98f4;background:#263653;color:#e5edff}.chat-view input[type="range"]{width:100%;padding:0}footer{display:flex;justify-content:flex-end;gap:8px;margin-top:24px}.primary{border-color:#648ff0!important;background:#426fcf!important;color:#fff!important}@media(max-width:700px){.settings{grid-template-columns:1fr;grid-template-rows:auto minmax(0,1fr)}.settings nav{display:none}.mobile-nav{display:grid;grid-template-columns:minmax(0,1fr) auto;align-items:end;gap:8px;padding:8px 12px;border-bottom:1px solid #292c34;background:#101115}.mobile-nav label{margin:0}.mobile-nav button{min-height:38px;padding:8px 12px;border:1px solid #3b3f49;border-radius:6px;background:#24272e;color:#ddd}.settings main{padding:18px}.grid{grid-template-columns:1fr}.controls{grid-template-columns:minmax(100px,1fr) 100px}.view-presets{grid-template-columns:repeat(2,minmax(0,1fr))}}</style>
